package com.yottastudios.ns.collabspace.workspace.service.impl;

import com.baomidou.mybatisplus.extension.service.impl.ServiceImpl;
import com.yottastudios.ns.collabspace.control.infrastructure.role.NodeRoleLevel;
import com.yottastudios.ns.collabspace.workspace.entity.SpaceNodeUserRoleCacheEntity;
import com.yottastudios.ns.collabspace.workspace.mapper.SpaceNodeUserRoleCacheMapper;
import com.yottastudios.ns.collabspace.workspace.service.ISpaceNodeUserRoleCacheService;
import lombok.extern.slf4j.Slf4j;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import org.springframework.util.CollectionUtils;

import java.util.ArrayList;
import java.util.Collections;
import java.util.List;
import java.util.Map;
import java.util.Objects;
import java.util.stream.Collectors;

@Slf4j
@Service
public class SpaceNodeUserRoleCacheServiceImpl extends ServiceImpl<SpaceNodeUserRoleCacheMapper, SpaceNodeUserRoleCacheEntity> implements ISpaceNodeUserRoleCacheService {

    @Override
    public List<SpaceNodeUserRoleCacheEntity> getByUserAndNodes(Long userId, List<Long> nodeIds) {
        return lambdaQuery()
                .eq(SpaceNodeUserRoleCacheEntity::getUserId, userId)
                .in(SpaceNodeUserRoleCacheEntity::getSpaceNodeId, nodeIds)
                .list();
    }

    @Override
    public List<SpaceNodeUserRoleCacheEntity> getBySpaceAndNode(String spaceId, Long nodeId) {
        return lambdaQuery()
                .eq(SpaceNodeUserRoleCacheEntity::getSpaceId, spaceId)
                .eq(SpaceNodeUserRoleCacheEntity::getSpaceNodeId, nodeId)
                .list();
    }

    @Override
    public List<Long> listUserIdsByspaceNodeIdsAndMinRole(List<Long> spaceNodeIds, NodeRoleLevel minRole) {
        if (CollectionUtils.isEmpty(spaceNodeIds) || minRole == null) {
            return Collections.emptyList();
        }
        return lambdaQuery()
                .in(SpaceNodeUserRoleCacheEntity::getSpaceNodeId, spaceNodeIds)
                .ge(SpaceNodeUserRoleCacheEntity::getRoleLevel, minRole.getLevel())
                .list()
                .stream()
                .map(SpaceNodeUserRoleCacheEntity::getUserId)
                .filter(Objects::nonNull)
                .distinct()
                .toList();
    }

    @Override
    @Transactional
    public List<SpaceNodeUserRoleCacheEntity> batchUpsert(List<SpaceNodeUserRoleCacheEntity> caches) {
        if (caches == null || caches.isEmpty()) {
            return new ArrayList<>();
        }

        // 按 uk_user_node(user_id, space_node_id) 去重，同 key 保留 roleLevel 较大的
        List<SpaceNodeUserRoleCacheEntity> deduped = caches.stream()
                .collect(Collectors.toMap(
                        e -> e.getUserId() + "_" + e.getSpaceNodeId(),
                        e -> e,
                        (a, b) -> a.getRoleLevel() != null && (b.getRoleLevel() == null
                                || a.getRoleLevel() >= b.getRoleLevel()) ? a : b
                ))
                .values().stream().toList();

        List<SpaceNodeUserRoleCacheEntity> existingRecords = lambdaQuery()
                .in(SpaceNodeUserRoleCacheEntity::getSpaceId, deduped.stream().map(SpaceNodeUserRoleCacheEntity::getSpaceId).distinct().collect(Collectors.toList()))
                .in(SpaceNodeUserRoleCacheEntity::getUserId, deduped.stream().map(SpaceNodeUserRoleCacheEntity::getUserId).distinct().collect(Collectors.toList()))
                .in(SpaceNodeUserRoleCacheEntity::getSpaceNodeId, deduped.stream().map(SpaceNodeUserRoleCacheEntity::getSpaceNodeId).distinct().collect(Collectors.toList()))
                .list();

        Map<String, SpaceNodeUserRoleCacheEntity> existingMap = existingRecords.stream()
                .collect(Collectors.toMap(
                        entity -> entity.getSpaceId() + "_" + entity.getUserId() + "_" + entity.getSpaceNodeId(),
                        entity -> entity
                ));

        List<SpaceNodeUserRoleCacheEntity> toInsert = new ArrayList<>();
        List<SpaceNodeUserRoleCacheEntity> toUpdate = new ArrayList<>();
        List<SpaceNodeUserRoleCacheEntity> changed = new ArrayList<>();

        for (SpaceNodeUserRoleCacheEntity cache : deduped) {
            String key = cache.getSpaceId() + "_" + cache.getUserId() + "_" + cache.getSpaceNodeId();
            SpaceNodeUserRoleCacheEntity existing = existingMap.get(key);

            if (existing == null) {
                if (cache.getRoleLevel() != null && cache.getRoleLevel() == 0) {
                    continue;
                }
                toInsert.add(cache);
                changed.add(cache);
            } else if (!existing.getRoleLevel().equals(cache.getRoleLevel())) {
                existing.setRoleLevel(cache.getRoleLevel());
                toUpdate.add(existing);
                changed.add(existing);
            }
        }

        if (!toInsert.isEmpty()) {
            saveBatch(toInsert);
        }

        if (!toUpdate.isEmpty()) {
            updateBatchById(toUpdate);
        }

        return changed;
    }

    @Override
    public List<SpaceNodeUserRoleCacheEntity> listBySpaceId(String spaceId) {
        return lambdaQuery()
                .eq(SpaceNodeUserRoleCacheEntity::getSpaceId, spaceId)
                .gt(SpaceNodeUserRoleCacheEntity::getRoleLevel, 0)
                .list();
    }
}

