  1→package com.yottastudios.ns.collabspace.workspace.permission.manager;
  2→
  3→import com.yottastudios.ns.collabspace.control.entity.ControlRoleEntity;
  4→import com.yottastudios.ns.collabspace.control.infrastructure.ControlRoleDict;
  5→import com.yottastudios.ns.collabspace.control.infrastructure.ControlTemplate;
  6→import com.yottastudios.ns.collabspace.control.infrastructure.role.ControlRole;
  7→import com.yottastudios.ns.collabspace.control.infrastructure.role.NodeRoleLevel;
  8→import com.yottastudios.ns.collabspace.control.service.IControlRoleService;
  9→import com.yottastudios.ns.collabspace.grpc.IApitableGrpcClientService;
 10→import com.yottastudios.ns.collabspace.third.dto.migrate.MemberEntity;
 11→import com.yottastudios.ns.collabspace.third.feign.ApitableMigrationFeign;
 12→import com.yottastudios.ns.collabspace.workspace.entity.SpaceNodeEntity;
 13→import com.yottastudios.ns.collabspace.workspace.entity.SpaceNodeUserRoleCacheEntity;
 14→import com.yottastudios.ns.collabspace.workspace.permission.model.PermissionScope;
 15→import com.yottastudios.ns.collabspace.workspace.permission.sync.PermissionBroadcaster;
 16→import com.yottastudios.ns.collabspace.workspace.service.ISpaceNodeService;
 17→import com.yottastudios.ns.collabspace.workspace.service.ISpaceNodeUserRoleCacheService;
 18→import com.yottastudios.ns.collabspace.workspace.dto.SimpleNodeInfo;
 19→import com.yottastudios.ns.collabspace.workspace.manager.query.NodeRoleQueryManager;
 20→import jakarta.annotation.Resource;
 21→import lombok.extern.slf4j.Slf4j;
 22→import org.apache.commons.collections4.CollectionUtils;
 23→import org.springframework.stereotype.Component;
 24→
 25→import java.util.ArrayList;
 26→import java.util.HashSet;
 27→import java.util.List;
 28→import java.util.Map;
 29→import java.util.Objects;
 30→import java.util.Set;
 31→import java.util.stream.Collectors;
 32→
 33→import static com.yottastudios.ns.collabspace.core.support.tree.v2.DefaultTreeBuildFactory.ROOT_PARENT_ID;
 34→
 35→@Slf4j
 36→@Component
 37→public class PermissionCacheManager {
 38→
 39→    @Resource
 40→    private ISpaceNodeUserRoleCacheService cacheService;
 41→    @Resource
 42→    private ControlTemplate controlTemplate;
 43→    @Resource
 44→    private IControlRoleService controlRoleService;
 45→    @Resource
 46→    private NodeRoleQueryManager nodeRoleQueryManager;
 47→    @Resource
 48→    private IApitableGrpcClientService apitableGrpcClientService;
 49→    @Resource
 50→    private PermissionBroadcaster permissionBroadcaster;
 51→    @Resource
 52→    private ISpaceNodeService spaceNodeService;
 53→    @Resource
 54→    private ApitableMigrationFeign apitableMigrationFeign;
 55→
 56→    public void updateAllNodesCacheAndBroadcast(String spaceId, Long userId) {
 57→        PermissionScope scope = new PermissionScope();
 58→        List<SpaceNodeEntity> spaceNodeEntities = spaceNodeService.listBySpaceId(spaceId, false);
 59→        if (CollectionUtils.isEmpty(spaceNodeEntities)) {
 60→            log.warn("No space nodes found for spaceId={}", spaceId);
 61→            return;
 62→        }
 63→        List<Long> spaceNodeIds = spaceNodeEntities.stream().map(SpaceNodeEntity::getId).toList();
 64→        scope.addUserId(userId);
 65→        scope.addSpaceNodeIds(spaceNodeIds);
 66→        updateCacheAndBroadcast(spaceId, scope);
 67→    }
 68→
 69→    public void updateAllNodesAndUsersCacheAndBroadcast(String spaceId) {
 70→        PermissionScope scope = new PermissionScope();
 71→        List<SpaceNodeEntity> spaceNodeEntities = spaceNodeService.listBySpaceId(spaceId, false);
 72→        if (CollectionUtils.isEmpty(spaceNodeEntities)) {
 73→            log.warn("No space nodes found for spaceId={}", spaceId);
 74→            return;
 75→        }
 76→        List<Long> userIds = listUserIdsBySpaceId(spaceId);
 77→        if (userIds == null) {
 78→            return;
 79→        }
 80→        List<Long> spaceNodeIds = spaceNodeEntities.stream().map(SpaceNodeEntity::getId).toList();
 81→        scope.addUserIds(userIds);
 82→        scope.addSpaceNodeIds(spaceNodeIds);
 83→        updateCacheAndBroadcast(spaceId, scope);
 84→    }
 85→
 86→    public void updateCacheAndBroadcast(String spaceId, PermissionScope scope) {
 87→        List<SpaceNodeUserRoleCacheEntity> changedRecords = updateCache(spaceId, scope);
 88→        permissionBroadcaster.broadcast(spaceId, changedRecords);
 89→    }
 90→
 91→    private List<SpaceNodeUserRoleCacheEntity> updateCache(String spaceId, PermissionScope scope) {
 92→        if (scope == null || spaceId == null) {
 93→            log.warn("Invalid parameters: spaceId={}, scope={}", spaceId, scope);
 94→            return new ArrayList<>();
 95→        }
 96→
 97→        Set<Long> userIds = scope.getUserIds();
 98→        Set<Long> scopeNodeIds = scope.getSpaceNodeIds();
 99→
100→        if (CollectionUtils.isEmpty(scopeNodeIds)) {
101→            log.info("Empty nodes in scope");
102→            return new ArrayList<>();
103→        }
104→
105→        if (CollectionUtils.isEmpty(userIds)) {
106→            log.info("Empty users in scope, calculating affected users from control roles");
107→            userIds = calculateAffectedUsers(scopeNodeIds);
108→            if (CollectionUtils.isEmpty(userIds)) {
109→                log.info("No affected users found for nodes");
110→                return new ArrayList<>();
111→            }
112→        }
113→
114→        log.info("Updating cache for {} users and {} nodes", userIds.size(), scopeNodeIds.size());
115→
116→        List<SpaceNodeUserRoleCacheEntity> cacheEntities = new ArrayList<>();
117→        List<Long> nodeIdList = new ArrayList<>(scopeNodeIds);
118→
119→        for (Long userId : userIds) {
120→            ControlRoleDict roleDict = controlTemplate.fetchSpaceNodeRoleRaw(userId, nodeIdList);
121→
122→            for (Long spaceNodeId : scopeNodeIds) {
123→                ControlRole role = roleDict != null ? roleDict.get(spaceNodeId.toString()) : null;
124→                Integer roleLevel = NodeRoleLevel.fromRole(role).getLevel();
125→
126→                SpaceNodeUserRoleCacheEntity entity = SpaceNodeUserRoleCacheEntity.builder()
127→                        .spaceId(spaceId)
128→                        .userId(userId)
129→                        .spaceNodeId(spaceNodeId)
130→                        .roleLevel(roleLevel)
131→                        .build();
132→
133→                cacheEntities.add(entity);
134→            }
135→        }
136→
137→        if (CollectionUtils.isEmpty(cacheEntities)) {
138→            log.info("No cache entries to upsert");
139→            return new ArrayList<>();
140→        }
141→
142→
143→        List<SpaceNodeUserRoleCacheEntity> changedEntities = cacheService.batchUpsert(cacheEntities);
144→        log.info("Batch upserting {} cache entries, changed {}", cacheEntities.size(), changedEntities.size());
145→        return changedEntities;
146→    }
147→
148→    private Set<Long> calculateAffectedUsers(Set<Long> nodeIds) {
149→        if (CollectionUtils.isEmpty(nodeIds)) {
150→            return new HashSet<>();
151→        }
152→
153→        List<Long> scopeNodeIds = new ArrayList<>(nodeIds);
154→        List<SimpleNodeInfo> nodeInfos = nodeRoleQueryManager.getNodeInfoWithPermissionStatus(scopeNodeIds);
155→        if (CollectionUtils.isEmpty(nodeInfos)) {
156→            return getSpaceMemberUserIds(nodeIds);
157→        }
158→
159→        Map<Long, SimpleNodeInfo> spaceNodeIdToInfo = nodeInfos.stream()
160→                .collect(Collectors.toMap(SimpleNodeInfo::getSpaceNodeId, v -> v, (a, b) -> a));
161→        Map<Long, SimpleNodeInfo> treeNodeIdToInfo = nodeInfos.stream()
162→                .collect(Collectors.toMap(SimpleNodeInfo::getNodeId, v -> v, (a, b) -> a));
163→
164→        Set<Long> roleNodeIds = new HashSet<>();
165→        Set<Long> unresolvedNodeIds = new HashSet<>();
166→        for (Long spaceNodeId : nodeIds) {
167→            SimpleNodeInfo self = spaceNodeIdToInfo.get(spaceNodeId);
168→            if (self == null) {
169→                unresolvedNodeIds.add(spaceNodeId);
170→                continue;
171→            }
172→            Long roleNodeId = resolveRoleNodeId(self, treeNodeIdToInfo);
173→            if (roleNodeId == null) {
174→                unresolvedNodeIds.add(spaceNodeId);
175→                continue;
176→            }
177→            roleNodeIds.add(roleNodeId);
178→        }
179→
180→        Set<Long> affectedUserIds = new HashSet<>();
181→        addUsersFromRoleNodes(roleNodeIds, affectedUserIds);
182→
183→        if (CollectionUtils.isNotEmpty(unresolvedNodeIds)) {
184→            affectedUserIds.addAll(getSpaceMemberUserIds(unresolvedNodeIds));
185→        }
186→
187→        return affectedUserIds;
188→    }
189→
190→    private void addUsersFromRoleNodes(Set<Long> roleNodeIds, Set<Long> affectedUserIds) {
191→        if (CollectionUtils.isEmpty(roleNodeIds)) {
192→            return;
193→        }
194→        List<ControlRoleEntity> controlRoles = controlRoleService.getByControlIds(roleNodeIds);
195→        if (CollectionUtils.isEmpty(controlRoles)) {
196→            return;
197→        }
198→        Set<Long> unitIds = controlRoles.stream()
199→                .map(ControlRoleEntity::getUnitId)
200→                .filter(Objects::nonNull)
201→                .collect(Collectors.toSet());
202→        if (CollectionUtils.isEmpty(unitIds)) {
203→            return;
204→        }
205→        Map<Long, List<Long>> unitUserMap = apitableGrpcClientService.getUserIdsByUnitIds(new ArrayList<>(unitIds));
206→        if (unitUserMap == null) {
207→            return;
208→        }
209→        unitUserMap.values().stream()
210→                .filter(Objects::nonNull)
211→                .flatMap(List::stream)
212→                .filter(Objects::nonNull)
213→                .forEach(affectedUserIds::add);
214→    }
215→
216→    private Set<Long> getSpaceMemberUserIds(Set<Long> nodeIds) {
217→        List<SpaceNodeEntity> spaceNodes = spaceNodeService.listByIds(new ArrayList<>(nodeIds));
218→        if (CollectionUtils.isEmpty(spaceNodes)) {
219→            return new HashSet<>();
220→        }
221→
222→        Set<Long> userIds = new HashSet<>();
223→        Set<String> spaceIds = spaceNodes.stream()
224→                .map(SpaceNodeEntity::getSpaceId)
225→                .filter(Objects::nonNull)
226→                .collect(Collectors.toSet());
227→
228→        for (String spaceId : spaceIds) {
229→            List<Long> memberUserIds = listUserIdsBySpaceId(spaceId);
230→            if (memberUserIds == null) {
231→                continue;
232→            }
233→            userIds.addAll(memberUserIds);
234→        }
235→
236→        return userIds;
237→    }
238→
239→    private List<Long> listUserIdsBySpaceId(String spaceId) {
240→        ApitableMigrationFeign.ResponseData<List<MemberEntity>> memberResp = apitableMigrationFeign.getSpaceMembers(spaceId);// todo 可以优化为grpc调用
241→        if (memberResp == null || !Boolean.TRUE.equals(memberResp.getSuccess()) || memberResp.getData() == null) {
242→            log.error("获取Apitable成员失败: {} resp:{}", spaceId, memberResp);
243→            return null;
244→        }
245→        return memberResp.getData().stream()
246→                .map(MemberEntity::getUserId)
247→                .filter(Objects::nonNull)
248→                .collect(Collectors.toList());
249→    }
250→
251→    private Long resolveRoleNodeId(SimpleNodeInfo self, Map<Long, SimpleNodeInfo> treeNodeIdToInfo) {
252→        if (self.getExtend() == null || Boolean.FALSE.equals(self.getExtend())) {
253→            return self.getSpaceNodeId();
254→        }
255→
256→        Long parentId = self.getParentId();
257→        while (parentId != null && !ROOT_PARENT_ID.equals(parentId)) {
258→            SimpleNodeInfo parent = treeNodeIdToInfo.get(parentId);
259→            if (parent == null) {
260→                return null;
261→            }
