package com.yottastudios.ns.collabspace.workspace.permission.manager;

import com.yottastudios.ns.collabspace.control.entity.ControlRoleEntity;
import com.yottastudios.ns.collabspace.control.infrastructure.ControlRoleDict;
import com.yottastudios.ns.collabspace.control.infrastructure.ControlTemplate;
import com.yottastudios.ns.collabspace.control.infrastructure.role.ControlRole;
import com.yottastudios.ns.collabspace.control.infrastructure.role.NodeRoleLevel;
import com.yottastudios.ns.collabspace.control.service.IControlRoleService;
import com.yottastudios.ns.collabspace.grpc.IApitableGrpcClientService;
import com.yottastudios.ns.collabspace.third.dto.migrate.MemberEntity;
import com.yottastudios.ns.collabspace.third.feign.ApitableMigrationFeign;
import com.yottastudios.ns.collabspace.workspace.entity.SpaceNodeEntity;
import com.yottastudios.ns.collabspace.workspace.entity.SpaceNodeUserRoleCacheEntity;
import com.yottastudios.ns.collabspace.workspace.permission.model.PermissionScope;
import com.yottastudios.ns.collabspace.workspace.permission.sync.PermissionBroadcaster;
import com.yottastudios.ns.collabspace.workspace.service.ISpaceNodeService;
import com.yottastudios.ns.collabspace.workspace.service.ISpaceNodeUserRoleCacheService;
import com.yottastudios.ns.collabspace.workspace.dto.SimpleNodeInfo;
import com.yottastudios.ns.collabspace.workspace.manager.query.NodeRoleQueryManager;
import jakarta.annotation.Resource;
import lombok.extern.slf4j.Slf4j;
import org.apache.commons.collections4.CollectionUtils;
import org.springframework.stereotype.Component;

import java.util.ArrayList;
import java.util.HashSet;
import java.util.List;
import java.util.Map;
import java.util.Objects;
import java.util.Set;
import java.util.stream.Collectors;

import static com.yottastudios.ns.collabspace.core.support.tree.v2.DefaultTreeBuildFactory.ROOT_PARENT_ID;

@Slf4j
@Component
public class PermissionCacheManager {

    @Resource
    private ISpaceNodeUserRoleCacheService cacheService;
    @Resource
    private ControlTemplate controlTemplate;
    @Resource
    private IControlRoleService controlRoleService;
    @Resource
    private NodeRoleQueryManager nodeRoleQueryManager;
    @Resource
    private IApitableGrpcClientService apitableGrpcClientService;
    @Resource
    private PermissionBroadcaster permissionBroadcaster;
    @Resource
    private ISpaceNodeService spaceNodeService;
    @Resource
    private ApitableMigrationFeign apitableMigrationFeign;

    public void updateAllNodesCacheAndBroadcast(String spaceId, Long userId) {
        PermissionScope scope = new PermissionScope();
        List<SpaceNodeEntity> spaceNodeEntities = spaceNodeService.listBySpaceId(spaceId, false);
        if (CollectionUtils.isEmpty(spaceNodeEntities)) {
            log.warn("No space nodes found for spaceId={}", spaceId);
            return;
        }
        List<Long> spaceNodeIds = spaceNodeEntities.stream().map(SpaceNodeEntity::getId).toList();
        scope.addUserId(userId);
        scope.addSpaceNodeIds(spaceNodeIds);
        updateCacheAndBroadcast(spaceId, scope);
    }

    public void updateAllNodesAndUsersCacheAndBroadcast(String spaceId) {
        PermissionScope scope = new PermissionScope();
        List<SpaceNodeEntity> spaceNodeEntities = spaceNodeService.listBySpaceId(spaceId, false);
        if (CollectionUtils.isEmpty(spaceNodeEntities)) {
            log.warn("No space nodes found for spaceId={}", spaceId);
            return;
        }
        List<Long> userIds = listUserIdsBySpaceId(spaceId);
        if (userIds == null) {
            return;
        }
        List<Long> spaceNodeIds = spaceNodeEntities.stream().map(SpaceNodeEntity::getId).toList();
        scope.addUserIds(userIds);
        scope.addSpaceNodeIds(spaceNodeIds);
        updateCacheAndBroadcast(spaceId, scope);
    }

    public void updateCacheAndBroadcast(String spaceId, PermissionScope scope) {
        List<SpaceNodeUserRoleCacheEntity> changedRecords = updateCache(spaceId, scope);
        permissionBroadcaster.broadcast(spaceId, changedRecords);
    }

    private List<SpaceNodeUserRoleCacheEntity> updateCache(String spaceId, PermissionScope scope) {
        if (scope == null || spaceId == null) {
            log.warn("Invalid parameters: spaceId={}, scope={}", spaceId, scope);
            return new ArrayList<>();
        }

        Set<Long> userIds = scope.getUserIds();
        Set<Long> scopeNodeIds = scope.getSpaceNodeIds();

        if (CollectionUtils.isEmpty(scopeNodeIds)) {
            log.info("Empty nodes in scope");
            return new ArrayList<>();
        }

        if (CollectionUtils.isEmpty(userIds)) {
            log.info("Empty users in scope, calculating affected users from control roles");
            userIds = calculateAffectedUsers(scopeNodeIds);
            if (CollectionUtils.isEmpty(userIds)) {
                log.info("No affected users found for nodes");
                return new ArrayList<>();
            }
        }

        log.info("Updating cache for {} users and {} nodes", userIds.size(), scopeNodeIds.size());

        List<SpaceNodeUserRoleCacheEntity> cacheEntities = new ArrayList<>();
        List<Long> nodeIdList = new ArrayList<>(scopeNodeIds);

        for (Long userId : userIds) {
            ControlRoleDict roleDict = controlTemplate.fetchSpaceNodeRoleRaw(userId, nodeIdList);

            for (Long spaceNodeId : scopeNodeIds) {
                ControlRole role = roleDict != null ? roleDict.get(spaceNodeId.toString()) : null;
                Integer roleLevel = NodeRoleLevel.fromRole(role).getLevel();

                SpaceNodeUserRoleCacheEntity entity = SpaceNodeUserRoleCacheEntity.builder()
                        .spaceId(spaceId)
                        .userId(userId)
                        .spaceNodeId(spaceNodeId)
                        .roleLevel(roleLevel)
                        .build();

                cacheEntities.add(entity);
            }
        }

        if (CollectionUtils.isEmpty(cacheEntities)) {
            log.info("No cache entries to upsert");
            return new ArrayList<>();
        }


        List<SpaceNodeUserRoleCacheEntity> changedEntities = cacheService.batchUpsert(cacheEntities);
        log.info("Batch upserting {} cache entries, changed {}", cacheEntities.size(), changedEntities.size());
        return changedEntities;
    }

    private Set<Long> calculateAffectedUsers(Set<Long> nodeIds) {
        if (CollectionUtils.isEmpty(nodeIds)) {
            return new HashSet<>();
        }

        List<Long> scopeNodeIds = new ArrayList<>(nodeIds);
        List<SimpleNodeInfo> nodeInfos = nodeRoleQueryManager.getNodeInfoWithPermissionStatus(scopeNodeIds);
        if (CollectionUtils.isEmpty(nodeInfos)) {
            return getSpaceMemberUserIds(nodeIds);
        }

        Map<Long, SimpleNodeInfo> spaceNodeIdToInfo = nodeInfos.stream()
                .collect(Collectors.toMap(SimpleNodeInfo::getSpaceNodeId, v -> v, (a, b) -> a));
        Map<Long, SimpleNodeInfo> treeNodeIdToInfo = nodeInfos.stream()
                .collect(Collectors.toMap(SimpleNodeInfo::getNodeId, v -> v, (a, b) -> a));

        Set<Long> roleNodeIds = new HashSet<>();
        Set<Long> unresolvedNodeIds = new HashSet<>();
        for (Long spaceNodeId : nodeIds) {
            SimpleNodeInfo self = spaceNodeIdToInfo.get(spaceNodeId);
            if (self == null) {
                unresolvedNodeIds.add(spaceNodeId);
                continue;
            }
            Long roleNodeId = resolveRoleNodeId(self, treeNodeIdToInfo);
            if (roleNodeId == null) {
                unresolvedNodeIds.add(spaceNodeId);
                continue;
            }
            roleNodeIds.add(roleNodeId);
        }

        Set<Long> affectedUserIds = new HashSet<>();
        addUsersFromRoleNodes(roleNodeIds, affectedUserIds);

        if (CollectionUtils.isNotEmpty(unresolvedNodeIds)) {
            affectedUserIds.addAll(getSpaceMemberUserIds(unresolvedNodeIds));
        }

        return affectedUserIds;
    }

    private void addUsersFromRoleNodes(Set<Long> roleNodeIds, Set<Long> affectedUserIds) {
        if (CollectionUtils.isEmpty(roleNodeIds)) {
            return;
        }
        List<ControlRoleEntity> controlRoles = controlRoleService.getByControlIds(roleNodeIds);
        if (CollectionUtils.isEmpty(controlRoles)) {
            return;
        }
        Set<Long> unitIds = controlRoles.stream()
                .map(ControlRoleEntity::getUnitId)
                .filter(Objects::nonNull)
                .collect(Collectors.toSet());
        if (CollectionUtils.isEmpty(unitIds)) {
            return;
        }
        Map<Long, List<Long>> unitUserMap = apitableGrpcClientService.getUserIdsByUnitIds(new ArrayList<>(unitIds));
        if (unitUserMap == null) {
            return;
        }
        unitUserMap.values().stream()
                .filter(Objects::nonNull)
                .flatMap(List::stream)
                .filter(Objects::nonNull)
                .forEach(affectedUserIds::add);
    }

    private Set<Long> getSpaceMemberUserIds(Set<Long> nodeIds) {
        List<SpaceNodeEntity> spaceNodes = spaceNodeService.listByIds(new ArrayList<>(nodeIds));
        if (CollectionUtils.isEmpty(spaceNodes)) {
            return new HashSet<>();
        }

        Set<Long> userIds = new HashSet<>();
        Set<String> spaceIds = spaceNodes.stream()
                .map(SpaceNodeEntity::getSpaceId)
                .filter(Objects::nonNull)
                .collect(Collectors.toSet());

        for (String spaceId : spaceIds) {
            List<Long> memberUserIds = listUserIdsBySpaceId(spaceId);
            if (memberUserIds == null) {
                continue;
            }
            userIds.addAll(memberUserIds);
        }

        return userIds;
    }

    private List<Long> listUserIdsBySpaceId(String spaceId) {
        ApitableMigrationFeign.ResponseData<List<MemberEntity>> memberResp = apitableMigrationFeign.getSpaceMembers(spaceId);// todo 可以优化为grpc调用
        if (memberResp == null || !Boolean.TRUE.equals(memberResp.getSuccess()) || memberResp.getData() == null) {
            log.error("获取Apitable成员失败: {} resp:{}", spaceId, memberResp);
            return null;
        }
        return memberResp.getData().stream()
                .map(MemberEntity::getUserId)
                .filter(Objects::nonNull)
                .collect(Collectors.toList());
    }

    private Long resolveRoleNodeId(SimpleNodeInfo self, Map<Long, SimpleNodeInfo> treeNodeIdToInfo) {
        if (self.getExtend() == null || Boolean.FALSE.equals(self.getExtend())) {
            return self.getSpaceNodeId();
        }

        Long parentId = self.getParentId();
        while (parentId != null && !ROOT_PARENT_ID.equals(parentId)) {
            SimpleNodeInfo parent = treeNodeIdToInfo.get(parentId);
            if (parent == null) {
                return null;
            }
            if (Boolean.FALSE.equals(parent.getExtend())) {
                return parent.getSpaceNodeId();
            }
            parentId = parent.getParentId();
        }
        return null;
    }
}

package com.yottastudios.ns.collabspace.core.entity;

import com.baomidou.mybatisplus.annotation.*;
import com.fasterxml.jackson.annotation.JsonFormat;
import lombok.*;
import lombok.experimental.Accessors;
import lombok.experimental.SuperBuilder;

import java.time.LocalDateTime;

@Data
@SuperBuilder(toBuilder = true)
@NoArgsConstructor
@AllArgsConstructor
@Accessors(chain = true)
public class  BaseEntity {
    /**
     * Primary Key
     */
    @TableId(value = "id", type = IdType.ASSIGN_ID)
    private Long id;

    /**
     * Delete Tag(0: No, 1: Yes)
     */
    @TableLogic
    private Integer isDeleted;

    /**
     * Creator
     */
    @TableField(fill = FieldFill.INSERT)
    private Long createdBy;

    /**
     * Updater
     */
    @TableField(fill = FieldFill.INSERT_UPDATE)
    private Long updatedBy;

    /**
     * Create Time
     */
    @JsonFormat(pattern = "yyyy-MM-dd HH:mm:ss")
    private LocalDateTime createdAt;

    /**
     * Update Time
     */
    @TableField(fill = FieldFill.INSERT_UPDATE)
    @JsonFormat(pattern = "yyyy-MM-dd HH:mm:ss")
    private LocalDateTime updatedAt;
}

