                        (a, b) -> a.getRoleLevel() != null && (b.getRoleLevel() == null
                                || a.getRoleLevel() >= b.getRoleLevel()) ? a : b
                ))
                .values().stream().toList();

        List<SpaceNodeUserRoleCacheEntity> existingRecords = lambdaQuery()
                .in(SpaceNodeUserRoleCacheEntity::getSpaceId, deduped.stream().map(SpaceNodeUserRoleCacheEntity::getSpaceId).distinct().collect(Collectors.toList()))
                .in(SpaceNodeUserRoleCacheEntity::getUserId, deduped.stream().map(SpaceNodeUserRoleCacheEntity::getUserId).distinct().collect(Collectors.toList()))
                .in(SpaceNodeUserRoleCacheEntity::getSpaceNodeId, deduped.stream().map(SpaceNodeUserRoleCacheEntity::getSpaceNodeId).distinct().collect(Collectors.toList()))
                .list();

